import '../Styles/UMAPStyles.css';
import { Component } from 'preact';
import Dropdown from 'react-bootstrap/Dropdown';
import DropdownButton from 'react-bootstrap/DropdownButton';
import { index } from 'd3';
import Switch from 'preact-material-components/Switch';
import 'preact-material-components/Switch/style.css';
class UmapComponent extends Component {

  constructor(props){
    super(props)
    this.state = {
      optionDropDown : 0, //opcion seleccionada del dropdownbutton umap
      titleDropDown:"Cocientes+#Ti/25/0.25",
      switch:false, //Switch "Colorize unselected points" (sin color=falso)
      switchHighlighted:false, //swicth "Only Highlighted Data"
    }
    this.update_UMAP = this.update_UMAP.bind(this);
    this.onSelect_dropdown = this.onSelect_dropdown.bind(this);
  }

  //se invoca antes de renderizar cuando se reciben nuevas propiedades o estados
  componentDidUpdate(prevProps){
    if(!(prevProps.highlighted_data.length == this.props.highlighted_data.length) ||
        ((this.props.flag!=1) && (prevProps.selected_data.length != this.props.selected_data.length)) )
      this.update_UMAP(this.props);
  }

  //Modifica el estado al seleccionar una opcion en dropdown
  onSelect_dropdown(evt){
    const options = ["Cocientes+#Ti/25/0.25","Cocientes+#Ti/50/0.25","Cocientes+#Ti/75/0.25",
    "Cocientes+TiO2/25/0.25","Cocientes+TiO2/50/0.25","Cocientes+TiO2/75/0.25","End Members","End Members EMG+"];
    this.props.callback_dropDownOption(parseInt(evt));
    this.setState({titleDropDown:options[parseInt(evt)]});
    this.setState({optionDropDown:parseInt(evt)},()=>this.update_UMAP(this.props));
  }

  /*
  * Método para dibujar el UMAP
  */
  update_UMAP(props){
    var UMAP_data = this.props.UMAP_data[this.state.optionDropDown];
    var data = this.props.data;

    var scaleColor = d3.scaleOrdinal()
		  .domain(["Alaskan ultramafic","Alkali/Lamprophyres","Basalt","Komatiite","Laterite","Layered intrusion","Metamorphic","Ophiolite","Xenoliths"])
		  .range(["#7986cb","#f06292", "#ff8a65", "#ffb74d", "#fff176", "#aed581", "#4db6ac","#64b5f6", "#ba68c8"])
      //.range(["#4D69DC","#9e0142", "#e95c47", "#fdbf6f", "#ffffbe", "#bfe5a0", "#54aead", "#5e4fa2", "#DC4DD8"])

    var categoryOrder = d3.scaleOrdinal()
  		 .domain(["Alaskan ultramafic","Alkali/Lamprophyres","Basalt","Komatiite","Laterite","Layered intrusion","Metamorphic","Ophiolite","Xenoliths"])
  		 .range([0,1,2,3,4,5,6,7,8])

    const subcats = [[],
                      ["alkali basalt etc","kimberlite","lamproite","lamprophyre","potassic"],
                      ["boninite","flood basalt","hawaii lava lake","island arc","ocean floor","ocean island","ophiolite","undefined"],
                      ["chromite cores amphibolite AUDK","chromite cores amphibolite ADK","chromite cores greenschist","sulphide"],
                      [],
                      ["chromitite","other","subvolc sills/dykes"],
                      ["none","magnetite rims greenschist","magnetite rims amphibolite"],
                      ["chromitite","high p alpine","ocean floor peridotite","chromite"],
                      ["basalts","island arc","kimberlites","ocean floor"]];

    // set the dimensions and margins of the graph
    var margin = {top: 10, right: 0, bottom: 0, left: 50},
    width = screen.height*0.9,
    height = screen.height*0.9;

    //Remove content
    d3.select("#umap-chart").selectAll("*").remove()
    d3.select("#legend").selectAll("*").remove()

    // append the svg object to the body of the page
    var svg = d3.select("#umap-chart")
      .append("svg")
      .attr("width", "100%")
      .attr("height", "100%")
      .call(d3.zoom().on("zoom", function () {
        if (event.altKey) {
          svg.attr("transform", d3.event.transform)
        }
      }))
      .append("g")
      .attr("transform",
        "translate(" + margin.left + "," + margin.top + ")");

    // Add X axis
    var x = d3.scaleLinear()
      .domain([d3.extent(UMAP_data.map(l=>l.umap1))[0], d3.extent(UMAP_data.map(l=>l.umap1))[1]])
      .range([ 0, width-260 ]);
      svg.append("g")
        .attr("transform", "translate(0," + (height) + ")")
        .attr('class', 'grid') // CSS class
        .call(d3.axisBottom(x))

    // Add Y axis
    var y = d3.scaleLinear()
    .domain([d3.extent(UMAP_data.map(l=>l.umap2))[0], d3.extent(UMAP_data.map(l=>l.umap2))[1]])
      .range([ height-260, 0]);
      svg.append("g")
        .attr('class', 'grid') // CSS class
        .call(d3.axisLeft(y))
        .attr("transform", "translate("+ (width) +",0 )")

    d3.select("#download").on("click", function() {
      d3.select(this)
        .attr("href", 'data:application/octet-stream;base64,' + btoa(d3.select("#umap-chart").html()))
        .attr("download", "viz.svg")
    })

/*
    if(UMAP_data.length>0){
      //Legend
      var svg_legend = d3.select("#legend").append("svg")
      .attr("width", "100%")
      .attr("height", "100%")

      // create a list of keys
      var keys = ["ALASKAN ULTRAMAFIC","ALKALI/LAMPROPHYRES","BASALT","KOMATIITE","LATERITE","LAYERED INTRUSION","METAMORPHIC","OPHIOLITE","XENOLITHS"]

      // Add one dot in the legend for each category.
      var size = 15
      svg_legend.selectAll("mydots")
        .data(keys)
        .enter()
        .append("rect")
          .attr("x", 0)
          .attr("y", function(d,i){ return 100 + i*(size+7)}) // 100 is where the first dot appears. 25 is the distance between dots
          .attr("width", size)
          .attr("height", size)
          .style("fill", function(d){ return scaleColor(d)})

      // Add one dot in the legend for each category.
      svg_legend.selectAll("mylabels")
        .data(keys)
        .enter()
        .append("text")
          .attr("x", 20)
          .attr("y", function(d,i){ return 100 + i*(size+7) + (size/2)}) // 100 is where the first dot appears. 25 is the distance between dots
          .style("fill", function(d){ return "#000"})
          .text(function(d){ return d})
          .attr("text-anchor", "left")
          .style("alignment-baseline", "middle")
    }*/

    let seleccionados_aux = props.selected_data;
    let switchValue = this.state.switch;
    let switchHighlighted =  this.state.switchHighlighted;
    let highlighted_data = props.highlighted_data;


    const symbol = [d3.symbolCircle,d3.symbolCross,d3.symbolDiamond2, d3.symbolTriangle,d3.symbolSquare, d3.symbolStar, d3.symbolCircle,d3.symbolCross];

    // Add dots
    var circles = svg.append('g')
      .selectAll("dot")
      .data(UMAP_data)
      .enter()
      .append("path")
      .attr("d", d3.symbol().type( function(d,i){
        if(subcats[categoryOrder(d.Category)].length==0)
            return d3.symbolCircle;
        else {
            var nsub =  subcats[categoryOrder(d.Category)].indexOf(data[i].Category2) ;
            return symbol[nsub];
        }
      }).size(5))
      .attr("transform", function(d) { return "translate(" + x(+d.umap1) + "," + y(+d.umap2) + ")"; })
      .style("fill",function(d,i){
          if(!switchValue && seleccionados_aux.length>0 && !seleccionados_aux.includes(i)){
            return "rgba(190, 190, 190,0.5)";
          }
          else {
            if(subcats[categoryOrder(d.Category)].length==0)
             return scaleColor(d.Category); //Alkali y Laterite
           else {
             var n = subcats[categoryOrder(d.Category)].length; //cantidad de subcategorias
             var color = d3.hsl(scaleColor(d.Category));
             var nsub =  subcats[categoryOrder(d.Category)].indexOf(data[i].Category2)+2; //por lo que se encuentra en la pos 0
             //return d3.hsl(color.h, (((color.s+0.2)/n)*nsub)+(color.s-0.1)  ,(((color.l+0.05)/n)*nsub)+(color.l-0.05));
             return d3.hsl(color.h, ((0.8-0.2)/(n+1))*nsub + 0.2  , ((0.8-0.2)/(n+1))*nsub + 0.2);

           };
          }
        })
        .style("stroke-width",0.3)
        .style("stroke",function(d,i){
           if(props.highlighted_data.includes(d.i))
               return "#000";
           else
               return "none";
         })
         .style('fill-opacity',function(d,i){
           if(props.highlighted_data.length>0){
             if(props.highlighted_data.includes(d.i))
               return 1;
            else
              return 0.7;
          }
           else
               return 1;
         });

         //detrital
         // Add dots
         let detrital_data = this.props.detrital;
         var detrital = svg.append('g')
           .selectAll("dot")
           .data(detrital_data)
           .enter()
           .append("path")
           .attr("d", d3.symbol().type( function(d,i){return d3.symbolCircle;}).size(5))
           .attr("transform", function(d) { return "translate(" + x(+d.umap1) + "," + y(+d.umap2) + ")"; })
           .style("fill", "rgba(0, 0, 0, 1)");



         // Lasso functions
         var lasso_start = function() {
               lasso.items()
                   .style("stroke","none")


               lasso.items()
                   .classed("not_possible",true)
                   .classed("selected",false);
         };

         var lasso_draw = function() {
             // Style the possible dots
             lasso.possibleItems()
             .style("stroke",function(d,i){
                if(props.highlighted_data.includes(d.i))
                    return "#000";
                else
                    return "none";
              })
             .style("fill", d=>  {
                 if(subcats[categoryOrder(d.Category)].length==0)
                   return scaleColor(d.Category); //Alkali y Laterite
                 else {
                   var n = subcats[categoryOrder(d.Category)].length; //cantidad de subcategorias
                   var color = d3.hsl(scaleColor(d.Category));
                   var nsub =  subcats[categoryOrder(d.Category)].indexOf(data[d.i].Category2)+2; //por lo que se encuentra en la pos 0
                   return d3.hsl(color.h, ((0.8-0.2)/(n+1))*nsub + 0.2  , ((0.8-0.2)/(n+1))*nsub + 0.2);
                 }
               });

             lasso.notPossibleItems()
                    .style("fill","rgba(190, 190, 190,0.5)");

         };

    var lasso_end = function(lasso,callback_selected_data,callback_setFlag) {
      // Reset the color of all dots
      lasso.items()
        .classed("not_possible",false)
        .classed("possible",false);

      // Style the selected dots
      lasso.selectedItems()
        .classed("selected",true)
        .attr("r",1);
      // Detect selected dots
      let index_seleccionados = [];
      for(let j=0; j<lasso.selectedItems()._groups[0].length; j++){
        index_seleccionados.push(lasso.selectedItems()._groups[0][j].__data__.i);
      }
      callback_selected_data(1,index_seleccionados);
      // Reset the style of the not selected dots
      lasso.notSelectedItems()
        .attr("r",0.5);
    };

    var callback_selected_data = this.props.callback_selected_data;
    var callback_setFlag = this.props.callback_setFlag;

    var lasso = d3.lasso()
      .closePathSelect(true)
      .closePathDistance(100)
      .items(circles)
      .targetArea(svg)
      .on("start",lasso_start)
      .on("draw",function() {
        lasso_draw(switchValue);
      })
      .on("end", function() {
        lasso_end(lasso,callback_selected_data,callback_setFlag);
      });

    svg.call(lasso);
  }

  render(){
    return (
      <div>
        <div class="container-UMAP">
          <DropdownButton id="dropdown-basic-button" title={this.state.titleDropDown} onSelect={(e)=>this.onSelect_dropdown(e)}>
            <Dropdown.Item eventKey={0}>Cocientes+#Ti/25/0.25</Dropdown.Item>
            <Dropdown.Item eventKey={1}>Cocientes+#Ti/50/0.25</Dropdown.Item>
            <Dropdown.Item eventKey={2}>Cocientes+#Ti/75/0.25</Dropdown.Item>
            <Dropdown.Item eventKey={3}>Cocientes+TiO2/25/0.25</Dropdown.Item>
            <Dropdown.Item eventKey={4}>Cocientes+TiO2/50/0.25</Dropdown.Item>
            <Dropdown.Item eventKey={5}>Cocientes+TiO2/75/0.25</Dropdown.Item>
            <Dropdown.Item eventKey={6}>End Members</Dropdown.Item>
            <Dropdown.Item eventKey={7}>End Members EMG+</Dropdown.Item>
          </DropdownButton>

          <div id="umap-chart"></div>
          <text class="textSwitch" >Colorize unselected items</text>
          <Switch checked={this.state.switch} onChange={e =>{this.setState({switch:!this.state.switch},()=>this.update_UMAP(this.props)); }}/>
          <a class="textSwitch" id="download" href="#">Download SVG</a>
        </div>


      </div>
    );
  }
}

//<text class="textSwitch" style={{marginLeft:"50px"}}>Colorize only highlighted items</text>
//<Switch checked={this.state.switchHighlighted} onChange={e =>{this.setState({switchHighlighted:!this.state.switchHighlighted},()=>this.update_UMAP(this.props)); }}/>

/*
<div class="container-legend">
  <div id="legend"></div>
</div>*/
export default UmapComponent;
